  export const SIGNIFICATIONS_MAISONS = {
    1: "identité et apparence", 2: "ressources et valeurs", 3: "communication et déplacements",
    4: "foyer et famille", 5: "créativité et plaisirs", 6: "santé et travail quotidien",
    7: "partenariats et relations", 8: "transformation et profondeur", 9: "voyages et spiritualité",
    10: "carrière et réputation", 11: "amis et communauté", 12: "inconscient et solitude"
  };
  
  // Fonction pour obtenir la variation des mouvements célestes
  export function getVariationMouvement(cleBase, jourAnnee) {
    const rythmes = {
      "Lune": { variations: 4, intervalle: 1 },
      "Mercure": { variations: 20, intervalle: 1 },
      "Vénus": { variations: 17, intervalle: 1.5 },
      "Mars": { variations: 22, intervalle: 2 },
      "Jupiter": { variations: 20, intervalle: 18 },
      "Saturne": { variations: 20, intervalle: 45 }
    };
    
    const planete = Object.keys(rythmes).find(p => cleBase.startsWith(p));
    if (!planete) return null;
    
    const { variations, intervalle } = rythmes[planete];
    const index = Math.floor(jourAnnee / intervalle) % variations;
    const cleVariation = `${cleBase}_mouvement_${index}`;
    
    return LECTURES_MAISONS[cleVariation] || LECTURES_MAISONS[cleBase] || null;
  }
  
  // Fonction pour obtenir la variation horoscope (detail étoffés) — rythmes spécifiques
  export function getVariationHoroscope(cleBase, jourAnnee) {
    const rythmesDetail = {
      "Lune": { variations: 4, intervalle: 1 },
      "Venus": { variations: 8, intervalle: 3 },
      "Mars": { variations: 11, intervalle: 4 }
    };
    
    const planete = Object.keys(rythmesDetail).find(p => cleBase.startsWith(p));
    if (!planete) return null;
    
    const { variations, intervalle } = rythmesDetail[planete];
    const index = Math.floor(jourAnnee / intervalle) % variations;
    const cleVariation = `${cleBase}_detail_${index}`;
    
    return LECTURES_MAISONS[cleVariation] || LECTURES_MAISONS[cleBase + "_detail"] || LECTURES_MAISONS[cleBase] || null;
  }